     1в†’/**
     2в†’ * MMS Run Assignment Optimizer
     3в†’ *
     4в†’ * Main optimizer service that orchestrates between C++ OR-Tools solver
     5в†’ * and TypeScript fallback. Provides IPC with the C++ binary via
     6в†’ * NDJSON streams on stdin/stdout.
     7в†’ *
     8в†’ * Architecture:
     9в†’ * - Primary: C++ OR-Tools CP-SAT solver for optimal solutions
    10в†’ * - Fallback: TypeScript greedy algorithm when C++ unavailable/timeout
    11в†’ * - Heartbeat monitoring to detect hung processes
    12в†’ * - Explanation traces for every assignment decision
    13в†’ *
    14в†’ * @see specs/002-architecture.md Section 2.4
    15в†’ * @see specs/004-domain-services.md Section 4.3
    16в†’ */
    17в†’
    18в†’import { spawn, type Subprocess } from 'bun';
    19в†’import { logger } from '../lib/logging/logger';
    20в†’import { withSpan, recordSpanError } from '../lib/tracing';
    21в†’import { OptimizerError } from '../lib/errors';
    22в†’import { optimizerMetrics } from '../lib/metrics';
    23в†’import { FallbackOptimizer, fallbackOptimizer } from './fallback';
    24в†’import {
    25в†’  type OptimizerFullInput,
    26в†’  type OptimizerFullResult,
    27в†’  type OptimizerMessage,
    28в†’  type OptimizerProgressMessage,
    29в†’  DEFAULT_OPTIMIZER_CONFIG,
    30в†’} from './types';
    31в†’
    32в†’// Re-export types
    33в†’export * from './types';
    34в†’export { FallbackOptimizer, fallbackOptimizer } from './fallback';
    35в†’
    36в†’// =============================================================================
    37в†’// Configuration
    38в†’// =============================================================================
    39в†’
    40в†’export interface RunAssignmentOptimizerConfig {
    41в†’  binaryPath: string;
    42в†’  maxSolveTimeSeconds: number;
    43в†’  timeoutMs: number;
    44в†’  fallbackEnabled: boolean;
    45в†’  heartbeatIntervalMs: number;
    46в†’  heartbeatTimeoutMs: number;
    47в†’}
    48в†’
    49в†’const DEFAULT_CONFIG: RunAssignmentOptimizerConfig = {
    50в†’  binaryPath: process.env['MMS_OPTIMIZER_BINARY'] || './mms-optimizer/build/mms-optimizer',
    51в†’  maxSolveTimeSeconds: 30,
    52в†’  timeoutMs: 60000,
    53в†’  fallbackEnabled: true,
    54в†’  heartbeatIntervalMs: 5000,
    55в†’  heartbeatTimeoutMs: 15000, // 3 missed heartbeats
    56в†’};
    57в†’
    58в†’// =============================================================================
    59в†’// Progress Callback
    60в†’// =============================================================================
    61в†’
    62в†’export type ProgressCallback = (progress: OptimizerProgressMessage) => void;
    63в†’
    64в†’// =============================================================================
    65в†’// Main Optimizer Service
    66в†’// =============================================================================
    67в†’
    68в†’/**
    69в†’ * Run Assignment Optimizer Service
    70в†’ *
    71в†’ * Manages the optimization process, handling both C++ binary
    72в†’ * execution and TypeScript fallback scenarios.
    73в†’ */
    74в†’export class RunAssignmentOptimizer {
    75в†’  private readonly config: RunAssignmentOptimizerConfig;
    76в†’  private readonly log = logger.child({ service: 'RunAssignmentOptimizer' });
    77в†’  private readonly fallback: FallbackOptimizer;
    78в†’  private process: Subprocess | null = null;
    79в†’  private heartbeatTimer: Timer | null = null;
    80в†’  private lastHeartbeat: number = 0;
    81в†’
    82в†’  constructor(config: Partial<RunAssignmentOptimizerConfig> = {}) {
    83в†’    this.config = { ...DEFAULT_CONFIG, ...config };
    84в†’    this.fallback = fallbackOptimizer;
    85в†’  }
    86в†’
    87в†’  /**
    88в†’   * Run optimization for train-to-route assignment
    89в†’   *
    90в†’   * @param input - Optimization input with trains, routes, and constraints
    91в†’   * @param onProgress - Optional callback for progress updates
    92в†’   * @returns Optimization result with assignments and explanations
    93в†’   */
    94в†’  async optimize(
    95в†’    input: OptimizerFullInput,
    96в†’    onProgress?: ProgressCallback
    97в†’  ): Promise<OptimizerFullResult> {
    98в†’    return withSpan('optimizer.optimize', async (span) => {
    99в†’      const startTime = Date.now();
   100в†’
   101в†’      span.setAttribute('requestId', input.requestId);
   102в†’      span.setAttribute('trainCount', input.trains.length);
   103в†’      span.setAttribute('routeCount', input.routes.length);
   104в†’      span.setAttribute('fallbackEnabled', this.config.fallbackEnabled);
   105в†’
   106в†’      // Merge default config with input config
   107в†’      const mergedInput: OptimizerFullInput = {
   108в†’        ...input,
   109в†’        config: { ...DEFAULT_OPTIMIZER_CONFIG, ...input.config },
   110в†’      };
   111в†’
   112в†’      this.log.info(
   113в†’        {
   114в†’          requestId: input.requestId,
   115в†’          trainCount: input.trains.length,
   116в†’          routeCount: input.routes.length,
   117в†’          assignmentDate: input.assignmentDate,
   118в†’        },
   119в†’        'Starting optimization'
   120в†’      );
   121в†’
   122в†’      try {
   123в†’        // Try C++ optimizer first
   124в†’        const result = await this.runCppOptimizer(mergedInput, onProgress);
   125в†’
   126в†’        // Check if C++ returned INFEASIBLE and fallback is enabled
   127в†’        if (result.status === 'INFEASIBLE' && this.config.fallbackEnabled) {
   128в†’          this.log.warn(
   129в†’            { requestId: input.requestId },
   130в†’            'C++ optimizer returned INFEASIBLE, using fallback'
   131в†’          );
   132в†’          return await this.runWithFallback(mergedInput, startTime);
   133в†’        }
   134в†’
   135в†’        optimizerMetrics.optimizerSolveSeconds
   136в†’          .labels('cpp', result.status)
   137в†’          .observe(result.solveTimeMs / 1000);
   138в†’
   139в†’        return result;
   140в†’      } catch (error) {
   141в†’        recordSpanError(span, error);
   142в†’
   143в†’        this.log.error(
   144в†’          { requestId: input.requestId, error },
   145в†’          'C++ optimizer failed'
   146в†’        );
   147в†’
   148в†’        if (this.config.fallbackEnabled) {
   149в†’          return await this.runWithFallback(mergedInput, startTime);
   150в†’        }
   151в†’
   152в†’        throw error;
   153в†’      }
   154в†’    });
   155в†’  }
   156в†’
   157в†’  /**
   158в†’   * Run only the TypeScript fallback optimizer
   159в†’   *
   160в†’   * Useful for testing or when C++ binary is not available.
   161в†’   */
   162в†’  async optimizeWithFallback(
   163в†’    input: OptimizerFullInput
   164в†’  ): Promise<OptimizerFullResult> {
   165в†’    const mergedInput: OptimizerFullInput = {
   166в†’      ...input,
   167в†’      config: { ...DEFAULT_OPTIMIZER_CONFIG, ...input.config },
   168в†’    };
   169в†’    return this.fallback.optimize(mergedInput);
   170в†’  }
   171в†’
   172в†’  /**
   173в†’   * Check if C++ optimizer binary is available
   174в†’   */
   175в†’  async isCppOptimizerAvailable(): Promise<boolean> {
   176в†’    try {
   177в†’      const proc = spawn(['test', '-x', this.config.binaryPath], {
   178в†’        stdout: 'pipe',
   179в†’        stderr: 'pipe',
   180в†’      });
   181в†’      const code = await proc.exited;
   182в†’      return code === 0;
   183в†’    } catch {
   184в†’      return false;
   185в†’    }
   186в†’  }
   187в†’
   188в†’  /**
   189в†’   * Run C++ optimizer binary
   190в†’   */
   191в†’  private async runCppOptimizer(
   192в†’    input: OptimizerFullInput,
   193в†’    onProgress?: ProgressCallback
   194в†’  ): Promise<OptimizerFullResult> {
   195в†’    return new Promise((resolve, reject) => {
   196в†’      const timeout = setTimeout(() => {
   197в†’        this.cleanup();
   198в†’        reject(
   199в†’          new OptimizerError(`Optimizer timeout after ${this.config.timeoutMs}ms`, {
   200в†’            requestId: input.requestId,
   201в†’            errorCode: 'TIMEOUT',
   202в†’          })
   203в†’        );
   204в†’      }, this.config.timeoutMs);
   205в†’
   206в†’      // Check if binary exists
   207в†’      const binaryCheck = spawn(['test', '-x', this.config.binaryPath], {
   208в†’        stdout: 'pipe',
   209в†’        stderr: 'pipe',
   210в†’      });
   211в†’
   212в†’      binaryCheck.exited.then((code) => {
   213в†’        if (code !== 0) {
   214в†’          clearTimeout(timeout);
   215в†’          reject(
   216в†’            new OptimizerError('C++ optimizer binary not found or not executable', {
   217в†’              requestId: input.requestId,
   218в†’              errorCode: 'BINARY_NOT_FOUND',
   219в†’              context: { binaryPath: this.config.binaryPath },
   220в†’            })
   221в†’          );
   222в†’          return;
   223в†’        }
   224в†’
   225в†’        // Spawn optimizer process
   226в†’        this.process = spawn([this.config.binaryPath], {
   227в†’          stdin: 'pipe',
   228в†’          stdout: 'pipe',
   229в†’          stderr: 'pipe',
   230в†’        });
   231в†’
   232в†’        // Start heartbeat monitor
   233в†’        this.startHeartbeatMonitor(input.requestId, () => {
   234в†’          clearTimeout(timeout);
   235в†’          this.cleanup();
   236в†’          reject(
   237в†’            new OptimizerError('Optimizer heartbeat timeout - process may be stuck', {
   238в†’              requestId: input.requestId,
   239в†’              errorCode: 'HEARTBEAT_TIMEOUT',
   240в†’            })
   241в†’          );
   242в†’        });
   243в†’
   244в†’        // Write input to stdin
   245в†’        const inputJson = JSON.stringify(this.transformInputForCpp(input)) + '\n';
   246в†’        const stdin = this.process.stdin;
   247в†’        if (stdin && typeof stdin === 'object' && 'getWriter' in stdin) {
   248в†’          const writer = (stdin as unknown as WritableStream<Uint8Array>).getWriter();
   249в†’          writer.write(new TextEncoder().encode(inputJson));
   250в†’          writer.close();
   251в†’        }
   252в†’
   253в†’        // Read stdout
   254в†’        const stdout = this.process.stdout;
   255в†’        if (stdout && typeof stdout === 'object' && 'getReader' in stdout) {
   256в†’          this.readOutputStream(
   257в†’            stdout as ReadableStream<Uint8Array>,
   258в†’            input.requestId,
   259в†’            onProgress,
   260в†’            (result) => {
   261в†’              clearTimeout(timeout);
   262в†’              this.cleanup();
   263в†’              resolve(result);
   264в†’            },
   265в†’            (error) => {
   266в†’              clearTimeout(timeout);
   267в†’              this.cleanup();
   268в†’              reject(error);
   269в†’            }
   270в†’          );
   271в†’        }
   272в†’
   273в†’        // Read stderr for logs
   274в†’        const stderr = this.process.stderr;
   275в†’        if (stderr && typeof stderr === 'object' && 'getReader' in stderr) {
   276в†’          this.readErrorStream(stderr as ReadableStream<Uint8Array>);
   277в†’        }
   278в†’
   279в†’        // Handle process exit
   280в†’        this.process.exited.then((code) => {
   281в†’          if (code !== 0) {
   282в†’            const signal = (this.process as unknown as { signalCode?: string })?.signalCode;
   283в†’            clearTimeout(timeout);
   284в†’            this.cleanup();
   285в†’            reject(
   286в†’              new OptimizerError(`Optimizer exited with code ${code}`, {
   287в†’                requestId: input.requestId,
   288в†’                errorCode: signal === 'SIGSEGV' ? 'SEGFAULT' : 'INTERNAL_ERROR',
   289в†’                context: { exitCode: code },
   290в†’              })
   291в†’            );
   292в†’          }
   293в†’        });
   294в†’      });
   295в†’    });
   296в†’  }
   297в†’
   298в†’  /**
   299в†’   * Transform input for C++ binary (snake_case)
   300в†’   */
   301в†’  private transformInputForCpp(input: OptimizerFullInput): Record<string, unknown> {
   302в†’    return {
   303в†’      type: 'SOLVE_REQUEST',
   304в†’      request_id: input.requestId,
   305в†’      assignment_date: input.assignmentDate,
   306в†’      config: {
   307в†’        max_solve_time_seconds: input.config.maxSolveTimeSeconds,
   308в†’        num_workers: input.config.numWorkers,
   309в†’        soft_constraint_penalties: {
   310в†’          mileage_imbalance: input.config.softConstraintPenalties.mileageImbalance,
   311в†’          preference_violation: input.config.softConstraintPenalties.preferenceViolation,
   312в†’          overtime_hours: input.config.softConstraintPenalties.overtimeHours,
   313в†’        },
   314в†’        explanation_verbosity: input.config.explanationVerbosity,
   315в†’      },
   316в†’      trains: input.trains.map((t) => ({
   317в†’        id: t.id,
   318в†’        train_number: t.trainNumber,
   319в†’        fleet_id: t.fleetId,
   320в†’        current_mileage: t.currentMileageKm,
   321в†’        target_mileage: t.targetMileageKm,
   322в†’        fitness_status: t.fitnessStatus,
   323в†’        restrictions: t.restrictions,
   324в†’        home_depot_id: t.homeDepotId,
   325в†’        current_depot_id: t.currentDepotId,
   326в†’      })),
   327в†’      routes: input.routes.map((r) => ({
   328в†’        id: r.id,
   329в†’        route_code: r.routeCode,
   330в†’        expected_km: r.expectedKmPerDay,
   331в†’        required_trains: r.requiredTrains,
   332в†’        allowed_fleets: r.allowedFleetIds,
   333в†’        restrictions: r.restrictions,
   334в†’      })),
   335в†’      hard_constraints: input.hardConstraints.map((c) => ({
   336в†’        type: c.type,
   337в†’        train_id: c.trainId,
   338в†’        route_id: c.routeId,
   339в†’        description: c.description,
   340в†’      })),
   341в†’      soft_constraints: input.softConstraints.map((c) => ({
   342в†’        type: c.type,
   343в†’        train_id: c.trainId,
   344в†’        penalty_weight: c.penaltyWeight,
   345в†’        description: c.description,
   346в†’      })),
   347в†’      unavailability_events: input.unavailabilityEvents?.map((e) => ({
   348в†’        train_id: e.trainId,
   349в†’        event_type: e.eventType,
   350в†’        status: e.status,
   351в†’        blocks_run_assignment: e.blocksRunAssignment,
   352в†’        description: e.description,
   353в†’        external_reference: e.externalReference,
   354в†’      })),
   355в†’      route_compatibility: input.routeCompatibility?.map((c) => ({
   356в†’        train_id: c.trainId,
   357в†’        fleet_id: c.fleetId,
   358в†’        route_id: c.routeId,
   359в†’        is_compatible: c.isCompatible,
   360в†’        constraint_type: c.constraintType,
   361в†’        restriction_reason: c.restrictionReason,
   362в†’      })),
   363в†’      material_positions: input.materialPositions?.map((p) => ({
   364в†’        depot_id: p.depotId,
   365в†’        part_number: p.partNumber,
   366в†’        quantity_available: p.quantityAvailable,
   367в†’        next_delivery_date: p.nextDeliveryDate,
   368в†’      })),
   369в†’      pending_pms: input.pendingPms?.map((pm) => ({
   370в†’        pm_id: pm.pmId,
   371в†’        train_id: pm.trainId,
   372в†’        pm_type: pm.pmType,
   373в†’        target_date: pm.targetDate,
   374в†’        required_materials: pm.requiredMaterials.map((m) => ({
   375в†’          part_number: m.partNumber,
   376в†’          quantity: m.quantity,
   377в†’          criticality: m.criticality,
   378в†’        })),
   379в†’      })),
   380в†’      service_demand: input.serviceDemand?.map((d) => ({
   381в†’        fleet_id: d.fleetId,
   382в†’        min_trains_required: d.minTrainsRequired,
   383в†’        day_type: d.dayType,
   384в†’      })),
   385в†’    };
   386в†’  }
   387в†’
   388в†’  /**
   389в†’   * Read and parse output stream
   390в†’   */
   391в†’  private async readOutputStream(
   392в†’    stream: ReadableStream<Uint8Array>,
   393в†’    requestId: string,
   394в†’    onProgress: ProgressCallback | undefined,
   395в†’    onResult: (result: OptimizerFullResult) => void,
   396в†’    onError: (error: Error) => void
   397в†’  ): Promise<void> {
   398в†’    const reader = stream.getReader();
   399в†’    const decoder = new TextDecoder();
   400в†’    let buffer = '';
   401в†’
   402в†’    try {
   403в†’      while (true) {
   404в†’        const { done, value } = await reader.read();
   405в†’        if (done) break;
   406в†’
   407в†’        buffer += decoder.decode(value, { stream: true });
   408в†’        const lines = buffer.split('\n');
   409в†’        buffer = lines.pop() || '';
   410в†’
   411в†’        for (const line of lines) {
   412в†’          if (!line.trim()) continue;
   413в†’
   414в†’          try {
   415в†’            const msg = JSON.parse(line) as OptimizerMessage;
   416в†’            this.handleMessage(msg, requestId, onProgress, onResult, onError);
   417в†’          } catch (parseError) {
   418в†’            this.log.warn({ line, parseError }, 'Failed to parse optimizer output');
   419в†’          }
   420в†’        }
   421в†’      }
   422в†’    } catch (error) {
   423в†’      this.log.error({ error }, 'Error reading optimizer output stream');
   424в†’      onError(error instanceof Error ? error : new Error(String(error)));
   425в†’    }
   426в†’  }
   427в†’
   428в†’  /**
   429в†’   * Handle parsed optimizer message
   430в†’   */
   431в†’  private handleMessage(
   432в†’    msg: OptimizerMessage,
   433в†’    requestId: string,
   434в†’    onProgress: ProgressCallback | undefined,
   435в†’    onResult: (result: OptimizerFullResult) => void,
   436в†’    onError: (error: Error) => void
   437в†’  ): void {
   438в†’    switch (msg.type) {
   439в†’      case 'HEARTBEAT':
   440в†’        this.lastHeartbeat = Date.now();
   441в†’        break;
   442в†’
   443в†’      case 'PROGRESS':
   444в†’        this.lastHeartbeat = Date.now();
   445в†’        if (onProgress) {
   446в†’          onProgress(msg);
   447в†’        }
   448в†’        break;
   449в†’
   450в†’      case 'ERROR':
   451в†’        onError(
   452в†’          new OptimizerError(msg.errorMessage, {
   453в†’            requestId,
   454в†’            errorCode: msg.errorCode,
   455в†’            recoverySuggestion: msg.recoverySuggestion,
   456в†’          })
   457в†’        );
   458в†’        break;
   459в†’
   460в†’      case 'RESULT':
   461в†’        onResult(this.transformResultFromCpp(msg as unknown as Record<string, unknown>));
   462в†’        break;
   463в†’    }
   464в†’  }
   465в†’
   466в†’  /**
   467в†’   * Transform result from C++ (snake_case to camelCase)
   468в†’   */
   469в†’  private transformResultFromCpp(msg: Record<string, unknown>): OptimizerFullResult {
   470в†’    const assignments = (msg['assignments'] as Record<string, unknown>[])?.map((a) => ({
   471в†’      trainId: a['train_id'] as string,
   472в†’      routeId: a['route_id'] as string,
   473в†’      score: a['score'] as number,
   474в†’      explanation: (a['explanation'] as Record<string, unknown>[])?.map((e) => ({
   475в†’        constraintType: e['constraint_type'] as 'HARD' | 'SOFT',
   476в†’        constraintName: e['constraint_name'] as string,
   477в†’        impact: e['impact'] as number,
   478в†’        description: e['description'] as string,
   479в†’      })) || [],
   480в†’    })) || [];
   481в†’
   482в†’    const unassigned = (msg['unassigned'] as Record<string, unknown>[])?.map((u) => ({
   483в†’      trainId: u['train_id'] as string | undefined,
   484в†’      routeId: u['route_id'] as string | undefined,
   485в†’      shortfall: u['shortfall'] as number | undefined,
   486в†’      reason: u['reason'] as string,
   487в†’      blockingConstraints: (u['blocking_constraints'] as string[]) || [],
   488в†’    })) || [];
   489в†’
   490в†’    const materialWarnings = (msg['material_warnings'] as Record<string, unknown>[])?.map((w) => ({
   491в†’      pmId: w['pm_id'] as string,
   492в†’      trainId: w['train_id'] as string,
   493в†’      partNumber: w['part_number'] as string,
   494в†’      status: w['status'] as 'UNAVAILABLE' | 'LOW_STOCK' | 'ARRIVING_LATE',
   495в†’      description: w['description'] as string,
   496в†’    })) || [];
   497в†’
   498в†’    const summary = msg['summary'] as Record<string, unknown>;
   499в†’
   500в†’    return {
   501в†’      type: 'RESULT',
   502в†’      requestId: msg['request_id'] as string,
   503в†’      status: msg['status'] as 'OPTIMAL' | 'FEASIBLE' | 'FALLBACK' | 'INFEASIBLE',
   504в†’      solveTimeMs: msg['solve_time_ms'] as number,
   505в†’      assignments,
   506в†’      unassigned,
   507в†’      materialWarnings,
   508в†’      summary: {
   509в†’        totalPenalty: summary?.['total_penalty'] as number || 0,
   510в†’        trainsAssigned: summary?.['trains_assigned'] as number || assignments.length,
   511в†’        trainsUnassigned: summary?.['trains_unassigned'] as number || unassigned.length,
   512в†’        softConstraintBreakdown: (summary?.['soft_constraint_breakdown'] as Record<string, number>) || {},
   513в†’        materialBlocks: summary?.['material_blocks'] as number || 0,
   514в†’      },
   515в†’    };
   516в†’  }
   517в†’
   518в†’  /**
   519в†’   * Read stderr for logs/metrics
   520в†’   */
   521в†’  private async readErrorStream(stream: ReadableStream<Uint8Array>): Promise<void> {
   522в†’    const reader = stream.getReader();
   523в†’    const decoder = new TextDecoder();
   524в†’
   525в†’    try {
   526в†’      while (true) {
   527в†’        const { done, value } = await reader.read();
   528в†’        if (done) break;
   529в†’
   530в†’        const text = decoder.decode(value, { stream: true });
   531в†’        for (const line of text.split('\n')) {
   532в†’          if (line.trim()) {
   533в†’            this.log.debug({ stderr: line }, 'Optimizer stderr');
   534в†’          }
   535в†’        }
   536в†’      }
   537в†’    } catch {
   538в†’      // Ignore stderr errors
   539в†’    }
   540в†’  }
   541в†’
   542в†’  /**
   543в†’   * Start heartbeat monitoring
   544в†’   */
   545в†’  private startHeartbeatMonitor(
   546в†’    requestId: string,
   547в†’    onTimeout: () => void
   548в†’  ): void {
   549в†’    this.lastHeartbeat = Date.now();
   550в†’
   551в†’    this.heartbeatTimer = setInterval(() => {
   552в†’      const elapsed = Date.now() - this.lastHeartbeat;
   553в†’
   554в†’      if (elapsed > this.config.heartbeatTimeoutMs) {
   555в†’        this.log.error(
   556в†’          { requestId, elapsedMs: elapsed },
   557в†’          'Heartbeat timeout - killing optimizer process'
   558в†’        );
   559в†’
   560в†’        // Kill hung process
   561в†’        if (this.process) {
   562в†’          this.process.kill('SIGKILL');
   563в†’        }
   564в†’
   565в†’        onTimeout();
   566в†’      }
   567в†’    }, this.config.heartbeatIntervalMs);
   568в†’  }
   569в†’
   570в†’  /**
   571в†’   * Run fallback optimizer
   572в†’   */
   573в†’  private async runWithFallback(
   574в†’    input: OptimizerFullInput,
   575в†’    startTime: number
   576в†’  ): Promise<OptimizerFullResult> {
   577в†’    this.log.info({ requestId: input.requestId }, 'Running fallback optimizer');
   578в†’
   579в†’    const result = await this.fallback.optimize(input);
   580в†’
   581в†’    optimizerMetrics.optimizerSolveSeconds
   582в†’      .labels('fallback', result.status)
   583в†’      .observe((Date.now() - startTime) / 1000);
   584в†’
   585в†’    return result;
   586в†’  }
   587в†’
   588в†’  /**
   589в†’   * Cleanup resources
   590в†’   */
   591в†’  private cleanup(): void {
   592в†’    if (this.heartbeatTimer) {
   593в†’      clearInterval(this.heartbeatTimer);
   594в†’      this.heartbeatTimer = null;
   595в†’    }
   596в†’
   597в†’    if (this.process) {
   598в†’      try {
   599в†’        this.process.kill();
   600в†’      } catch {
   601в†’        // Ignore kill errors
   602в†’      }
   603в†’      this.process = null;
   604в†’    }
   605в†’  }
   606в†’}
   607в†’
   608в†’// Export singleton instance
   609в†’export const runAssignmentOptimizer = new RunAssignmentOptimizer();
   610в†’

