   214в†’  }
   215в†’
   216в†’  /**
   217в†’   * Get sorted trains by mileage balance (under-utilized first)
   218в†’   */
   219в†’  private getSortedTrains(trains: OptimizerTrainInput[]): OptimizerTrainInput[] {
   220в†’    return [...trains]
   221в†’      .filter((t) => t.fitnessStatus === 'FIT')
   222в†’      .sort((a, b) => {
