   230в†’  /**
   231в†’   * Get set of unavailable train IDs from events
   232в†’   */
   233в†’  private getUnavailableTrainIds(input: OptimizerFullInput): Set<string> {
   234в†’    const unavailable = new Set<string>();
   235в†’
   236в†’    if (input.unavailabilityEvents) {
   237в†’      for (const event of input.unavailabilityEvents) {
   238в†’        if (event.status === 'ACTIVE' && event.blocksRunAssignment) {
   239в†’          unavailable.add(event.trainId);
   240в†’        }
   241в†’      }
   242в†’    }
   243в†’
   244в†’    return unavailable;
   245в†’  }
   246в†’
   247в†’  /**
   248в†’   * Build map of train ID to hard constraints
   249в†’   */
   250в†’  private buildTrainConstraintMap(
   251в†’    input: OptimizerFullInput
   252в†’  ): Map<string, string[]> {
   253в†’    const map = new Map<string, string[]>();
   254в†’
   255в†’    for (const constraint of input.hardConstraints) {
   256в†’      const existing = map.get(constraint.trainId) || [];
   257в†’      existing.push(constraint.description);
   258в†’      map.set(constraint.trainId, existing);
   259в†’    }
   260в†’
   261в†’    return map;
   262в†’  }
   263в†’
   264в†’  /**
   265в†’   * Build map of train+route to compatibility info
   266в†’   */
   267в†’  private buildRouteCompatibilityMap(
   268в†’    input: OptimizerFullInput
   269в†’  ): Map<string, boolean> {
   270в†’    const map = new Map<string, boolean>();
   271в†’
   272в†’    if (input.routeCompatibility) {
   273в†’      for (const compat of input.routeCompatibility) {
   274в†’        if (compat.trainId) {
   275в†’          const key = `${compat.trainId}:${compat.routeId}`;
   276в†’          map.set(key, compat.isCompatible);
   277в†’        }
   278в†’      }
   279в†’    }
   280в†’
   281в†’    return map;
   282в†’  }
   283в†’
   284в†’  /**
   285в†’   * Check hard constraints for a train-route pair
   286в†’   * Returns blocking reason or null if valid
   287в†’   */
   288в†’  private checkHardConstraints(
   289в†’    train: OptimizerTrainInput,
   290в†’    route: OptimizerRouteInput,
   291в†’    input: OptimizerFullInput,
   292в†’    unavailableTrainIds: Set<string>,
   293в†’    trainConstraintMap: Map<string, string[]>,
   294в†’    routeCompatibilityMap: Map<string, boolean>
   295в†’  ): string | null {
   296в†’    // Check fitness status
   297в†’    if (train.fitnessStatus !== 'FIT') {
   298в†’      return `Train is ${train.fitnessStatus}`;
   299в†’    }
   300в†’
   301в†’    // Check unavailability events
   302в†’    if (unavailableTrainIds.has(train.id)) {
   303в†’      const event = input.unavailabilityEvents?.find(
   304в†’        (e) => e.trainId === train.id && e.status === 'ACTIVE'
   305в†’      );
   306в†’      return `Train unavailable: ${event?.eventType || 'Unknown'} - ${
   307в†’        event?.description || event?.externalReference || 'No details'
   308в†’      }`;
   309в†’    }
   310в†’
   311в†’    // Check explicit hard constraints
   312в†’    const constraints = trainConstraintMap.get(train.id);
   313в†’    if (constraints && constraints.length > 0) {
   314в†’      return constraints[0];
   315в†’    }
   316в†’
   317в†’    // Check route compatibility
   318в†’    const compatKey = `${train.id}:${route.id}`;
   319в†’    if (routeCompatibilityMap.has(compatKey) && !routeCompatibilityMap.get(compatKey)) {
   320в†’      const compat = input.routeCompatibility?.find(
   321в†’        (c) => c.trainId === train.id && c.routeId === route.id
   322в†’      );
   323в†’      return `Route incompatible: ${compat?.constraintType || 'Technical'} - ${
   324в†’        compat?.restrictionReason || 'Restriction'
   325в†’      }`;
   326в†’    }
   327в†’
   328в†’    // Check pending PMs due today that block assignment
   329в†’    const today = input.assignmentDate;
   330в†’    if (input.pendingPms) {
   331в†’      for (const pm of input.pendingPms) {
   332в†’        if (pm.trainId === train.id && pm.targetDate <= today) {
   333в†’          // Check if blocking materials are unavailable
   334в†’          const hasBlockingMaterial = pm.requiredMaterials.some((mat) => {
   335в†’            if (mat.criticality !== 'BLOCKING') return false;
   336в†’
   337в†’            const position = input.materialPositions?.find(
   338в†’              (p) =>
   339в†’                p.partNumber === mat.partNumber &&
   340в†’                p.depotId === train.homeDepotId
   341в†’            );
   342в†’
   343в†’            return !position || position.quantityAvailable < mat.quantity;
   344в†’          });
   345в†’
   346в†’          if (!hasBlockingMaterial) {
   347в†’            return `PM ${pm.pmType} due today - train needs maintenance`;
   348в†’          }
   349в†’        }
   350в†’      }
   351в†’    }
   352в†’
   353в†’    return null;
   354в†’  }
   355в†’
   356в†’  /**
   357в†’   * Generate explanation traces for an assignment
   358в†’   */
   359в†’  private generateExplanation(
   360в†’    train: OptimizerTrainInput,
   361в†’    route: OptimizerRouteInput,
   362в†’    input: OptimizerFullInput
   363в†’  ): ExplanationTrace[] {
   364в†’    const explanation: ExplanationTrace[] = [];
   365в†’    const verbosity = input.config.explanationVerbosity;
   366в†’
   367в†’    // Mileage balance explanation
   368в†’    const mileageBalance = train.currentMileageKm - train.targetMileageKm;
   369в†’    const mileageImpact =
   370в†’      (Math.abs(mileageBalance) / 1000) *
   371в†’      input.config.softConstraintPenalties.mileageImbalance;
   372в†’
   373в†’    explanation.push({
   374в†’      constraintType: 'SOFT',
   375в†’      constraintName: 'MILEAGE_BALANCE',
   376в†’      impact: mileageBalance < 0 ? -mileageImpact : mileageImpact,
   377в†’      description: `Train is ${Math.abs(mileageBalance).toLocaleString()}km ${
   378в†’        mileageBalance < 0 ? 'under' : 'over'
   379в†’      } target mileage`,
   380в†’    });
   381в†’
   382в†’    // Depot preference explanation
   383в†’    if (train.homeDepotId !== train.currentDepotId) {
   384в†’      const depotImpact = input.config.softConstraintPenalties.preferenceViolation;
   385в†’      explanation.push({
   386в†’        constraintType: 'SOFT',
   387в†’        constraintName: 'DEPOT_PREFERENCE',
   388в†’        impact: depotImpact,
   389в†’        description: `Train is away from home depot`,
   390в†’      });
   391в†’    }
   392в†’
   393в†’    // Route expected km explanation (detailed mode)
   394в†’    if (verbosity === 'DETAILED') {
   395в†’      explanation.push({
   396в†’        constraintType: 'SOFT',
   397в†’        constraintName: 'ROUTE_UTILIZATION',
   398в†’        impact: 0,
   399в†’        description: `Route ${route.routeCode} expected to add ${route.expectedKmPerDay}km`,
   400в†’      });
   401в†’    }
   402в†’
   403в†’    // Soft constraint penalties from input
   404в†’    for (const constraint of input.softConstraints) {
   405в†’      if (constraint.trainId === train.id) {
   406в†’        explanation.push({
   407в†’          constraintType: 'SOFT',
   408в†’          constraintName: constraint.type,
   409в†’          impact: constraint.penaltyWeight,
   410в†’          description: constraint.description,
   411в†’        });
   412в†’      }
   413в†’    }
   414в†’
   415в†’    return explanation;
   416в†’  }
   417в†’
   418в†’  /**
   419в†’   * Calculate assignment score (lower is better)
   420в†’   */
   421в†’  private calculateScore(
   422в†’    train: OptimizerTrainInput,
   423в†’    route: OptimizerRouteInput,
   424в†’    input: OptimizerFullInput,
   425в†’    explanation: ExplanationTrace[]
   426в†’  ): number {
   427в†’    // Base score from soft constraint impacts
   428в†’    let score = explanation.reduce((sum, exp) => {
   429в†’      if (exp.constraintType === 'SOFT') {
   430в†’        return sum + Math.abs(exp.impact);
   431в†’      }
   432в†’      return sum;
   433в†’    }, 0);
   434в†’
   435в†’    // Bonus for under-utilized trains (negative balance = lower score)
   436в†’    const mileageBalance = train.currentMileageKm - train.targetMileageKm;
   437в†’    if (mileageBalance < 0) {
   438в†’      score -= Math.abs(mileageBalance) / 100;
   439в†’    }
   440в†’
   441в†’    // Penalty for high-mileage trains
   442в†’    if (mileageBalance > 0) {
   443в†’      score += mileageBalance / 50;
   444в†’    }
   445в†’
   446в†’    return Math.round(score * 100) / 100;
   447в†’  }
   448в†’
   449в†’  /**
   450в†’   * Calculate total penalty across all assignments
   451в†’   */
   452в†’  private calculateTotalPenalty(assignments: Assignment[]): number {
   453в†’    return assignments.reduce((sum, a) => sum + a.score, 0);
   454в†’  }
   455в†’
   456в†’  /**
   457в†’   * Find blocking reason for unassigned train
   458в†’   */
   459в†’  private findBlockingReason(
   460в†’    train: OptimizerTrainInput,
   461в†’    input: OptimizerFullInput,
   462в†’    unavailableTrainIds: Set<string>,
   463в†’    trainConstraintMap: Map<string, string[]>
   464в†’  ): string {
   465в†’    if (train.fitnessStatus !== 'FIT') {
   466в†’      return `Train is ${train.fitnessStatus}`;
   467в†’    }
   468в†’
   469в†’    if (unavailableTrainIds.has(train.id)) {
   470в†’      const event = input.unavailabilityEvents?.find(
   471в†’        (e) => e.trainId === train.id && e.status === 'ACTIVE'
   472в†’      );
   473в†’      return `Unavailable: ${event?.eventType || 'CM event'}`;
   474в†’    }
   475в†’
   476в†’    const constraints = trainConstraintMap.get(train.id);
   477в†’    if (constraints && constraints.length > 0) {
   478в†’      return constraints[0];
   479в†’    }
   480в†’
   481в†’    return 'No compatible route available or all routes fully staffed';
   482в†’  }
   483в†’
   484в†’  /**
   485в†’   * Get list of blocking constraints for a train
   486в†’   */
   487в†’  private getBlockingConstraints(
   488в†’    train: OptimizerTrainInput,
   489в†’    input: OptimizerFullInput,
   490в†’    trainConstraintMap: Map<string, string[]>
   491в†’  ): string[] {
   492в†’    const constraints: string[] = [];
   493в†’
   494в†’    if (train.fitnessStatus !== 'FIT') {
   495в†’      constraints.push(`FITNESS: ${train.fitnessStatus}`);
   496в†’    }
   497в†’
   498в†’    const hardConstraints = trainConstraintMap.get(train.id);
   499в†’    if (hardConstraints) {
   500в†’      constraints.push(...hardConstraints.map((c) => `HARD: ${c}`));
   501в†’    }
   502в†’
   503в†’    const activeEvent = input.unavailabilityEvents?.find(
   504в†’      (e) => e.trainId === train.id && e.status === 'ACTIVE'
   505в†’    );
   506в†’    if (activeEvent) {
   507в†’      constraints.push(`UNAVAILABLE: ${activeEvent.eventType}`);
   508в†’    }
   509в†’
   510в†’    return constraints;
   511в†’  }
   512в†’
   513в†’  /**
   514в†’   * Check material warnings for pending PMs
   515в†’   */
   516в†’  private checkMaterialWarnings(input: OptimizerFullInput): MaterialWarning[] {
   517в†’    const warnings: MaterialWarning[] = [];
   518в†’
   519в†’    if (!input.pendingPms || !input.materialPositions) {
   520в†’      return warnings;
   521в†’    }
   522в†’
   523в†’    const trainMap = new Map(input.trains.map((t) => [t.id, t]));
   524в†’    const today = new Date(input.assignmentDate);
   525в†’    const warningThresholdDays = 14;
   526в†’
   527в†’    for (const pm of input.pendingPms) {
   528в†’      const train = trainMap.get(pm.trainId);
   529в†’      if (!train) continue;
   530в†’
   531в†’      const pmDate = new Date(pm.targetDate);
   532в†’      const daysUntilPm = Math.ceil(
   533в†’        (pmDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24)
   534в†’      );
   535в†’
   536в†’      for (const mat of pm.requiredMaterials) {
   537в†’        if (mat.criticality !== 'BLOCKING') continue;
   538в†’
   539в†’        const position = input.materialPositions.find(
   540в†’          (p) =>
   541в†’            p.partNumber === mat.partNumber && p.depotId === train.homeDepotId
   542в†’        );
   543в†’
   544в†’        if (!position || position.quantityAvailable < mat.quantity) {
   545в†’          // Check if delivery will arrive in time
   546в†’          if (position?.nextDeliveryDate) {
   547в†’            const deliveryDate = new Date(position.nextDeliveryDate);
   548в†’            if (deliveryDate > pmDate) {
   549в†’              warnings.push({
   550в†’                pmId: pm.pmId,
   551в†’                trainId: pm.trainId,
   552в†’                partNumber: mat.partNumber,
   553в†’                status: 'ARRIVING_LATE',
   554в†’                description: `Part ${mat.partNumber} delivery expected ${position.nextDeliveryDate}, after PM date ${pm.targetDate}`,
   555в†’              });
   556в†’            }
   557в†’          } else if (daysUntilPm <= warningThresholdDays) {
   558в†’            warnings.push({
   559в†’              pmId: pm.pmId,
   560в†’              trainId: pm.trainId,
   561в†’              partNumber: mat.partNumber,
   562в†’              status: position ? 'LOW_STOCK' : 'UNAVAILABLE',
   563в†’              description: `Part ${mat.partNumber} unavailable at depot, ${
   564в†’                mat.quantity
   565в†’              } required, ${position?.quantityAvailable || 0} available`,
   566в†’            });
   567в†’          }
   568в†’        }
   569в†’      }
   570в†’    }
   571в†’
   572в†’    return warnings;
   573в†’  }
   574в†’
   575в†’  /**
   576в†’   * Validate service demand constraints
   577в†’   */
   578в†’  private validateServiceDemand(
   579в†’    input: OptimizerFullInput,
   580в†’    assignments: Assignment[],
   581в†’    unassigned: UnassignedTrain[]
   582в†’  ): void {
   583в†’    if (!input.serviceDemand) return;
   584в†’
   585в†’    // Count assigned trains per fleet
   586в†’    const trainMap = new Map(input.trains.map((t) => [t.id, t]));
   587в†’    const assignedByFleet = new Map<string, number>();
   588в†’
   589в†’    for (const assignment of assignments) {
   590в†’      const train = trainMap.get(assignment.trainId);
   591в†’      if (train) {
   592в†’        const count = assignedByFleet.get(train.fleetId) || 0;
   593в†’        assignedByFleet.set(train.fleetId, count + 1);
   594в†’      }
   595в†’    }
   596в†’
   597в†’    // Check each fleet's service demand
   598в†’    for (const demand of input.serviceDemand) {
   599в†’      const assigned = assignedByFleet.get(demand.fleetId) || 0;
   600в†’      if (assigned < demand.minTrainsRequired) {
   601в†’        unassigned.push({
   602в†’          reason: `Service demand violation: Fleet ${demand.fleetId} requires ${demand.minTrainsRequired} trains, only ${assigned} assigned`,
   603в†’          blockingConstraints: [
   604в†’            `SERVICE_DEMAND: ${demand.minTrainsRequired} required`,
   605в†’            `AVAILABLE: ${assigned} assigned`,
   606в†’          ],
   607в†’        });
   608в†’
   609в†’        this.log.warn(
   610в†’          {
   611в†’            fleetId: demand.fleetId,
   612в†’            required: demand.minTrainsRequired,
   613в†’            assigned,
   614в†’            dayType: demand.dayType,
   615в†’          },
   616в†’          'Service demand violation detected'
   617в†’        );
   618в†’      }
   619в†’    }
   620в†’  }
   621в†’}
   622в†’
   623в†’// Export singleton instance
   624в†’export const fallbackOptimizer = new FallbackOptimizer();
