     1в†’/**
     2в†’ * MMS Optimizer Worker Processor
     3в†’ *
     4в†’ * BullMQ job processor for run assignment optimization.
     5в†’ * Handles job lifecycle, progress reporting, and result storage.
     6в†’ *
     7в†’ * Job Flow:
     8в†’ * 1. Receive OptimizerJobData from queue
     9в†’ * 2. Fetch trains, routes, constraints from database
    10в†’ * 3. Build OptimizerFullInput
    11в†’ * 4. Run optimizer (C++ or fallback)
    12в†’ * 5. Store results and broadcast via WebSocket
    13в†’ *
    14в†’ * @see specs/002-architecture.md Section 2.2.4
    15в†’ * @see specs/004-domain-services.md Section 4.3
    16в†’ */
    17в†’
    18в†’import { logger } from '../../lib/logging/logger';
    19в†’import { withSpan } from '../../lib/tracing';
    20в†’import { db } from '../../lib/db/connection';
    21в†’import { ValidationError } from '../../lib/errors';
    22в†’import { optimizerMetrics } from '../../lib/metrics';
    23в†’import { type WorkerJobContext } from '../index';
    24в†’import { type OptimizerJobData } from '../../lib/queue';
    25в†’import {
    26в†’  runAssignmentOptimizer,
    27в†’  type OptimizerFullInput,
    28в†’  type OptimizerFullResult,
    29в†’  type OptimizerTrainInput,
    30в†’  type OptimizerRouteInput,
    31в†’  type HardConstraint,
    32в†’  type SoftConstraint,
    33в†’  type UnavailabilityEvent,
    34в†’  type ServiceDemand,
    35в†’  DEFAULT_OPTIMIZER_CONFIG,
    36в†’} from '../../optimizer';
    37в†’
    38в†’// Import database schemas
    39в†’import { trains, fleets, unavailabilityEvents, serviceDemand, runAssignments } from '../../lib/db/schema';
    40в†’import { eq, and, sql } from 'drizzle-orm';
    41в†’
    42в†’// =============================================================================
    43в†’// Worker Configuration
    44в†’// =============================================================================
    45в†’
    46в†’const log = logger.child({ worker: 'optimizer' });
    47в†’
    48в†’// =============================================================================
    49в†’// Job Processor
    50в†’// =============================================================================
    51в†’
    52в†’/**
    53в†’ * Process optimizer job
    54в†’ *
    55в†’ * Fetches required data, builds input, runs optimization,
    56в†’ * and stores/broadcasts results.
    57в†’ */
    58в†’export async function processOptimizerJob(
    59в†’  context: WorkerJobContext<OptimizerJobData>
    60в†’): Promise<OptimizerFullResult> {
    61в†’  return withSpan('worker.optimizer.process', async (span) => {
    62в†’    const { id, data } = context;
    63в†’    const { date, fleetId, constraints, timeoutMs } = data;
    64в†’
    65в†’    span.setAttribute('jobId', id);
    66в†’    span.setAttribute('date', date);
    67в†’    span.setAttribute('fleetId', fleetId);
    68в†’    span.setAttribute('hasConstraints', !!constraints);
    69в†’
    70в†’    log.info({ jobId: id, date, fleetId }, 'Processing optimizer job');
    71в†’
    72в†’    // Update progress: fetching data
    73в†’    await context.updateProgress({ stage: 'FETCHING_DATA', percent: 10 });
    74в†’    await context.log('Fetching trains and routes from database');
    75в†’
    76в†’    // Build optimizer input
    77в†’    const input = await buildOptimizerInput(date, fleetId, constraints, timeoutMs);
    78в†’
    79в†’    // Update progress: optimizing
    80в†’    await context.updateProgress({ stage: 'OPTIMIZING', percent: 30 });
    81в†’    await context.log(`Starting optimization for ${input.trains.length} trains, ${input.routes.length} routes`);
    82в†’
    83в†’    // Run optimization with progress callback
    84в†’    const result = await runAssignmentOptimizer.optimize(input, async (progress) => {
    85в†’      await context.updateProgress({
    86в†’        stage: 'OPTIMIZING',
    87в†’        percent: 30 + Math.floor(progress.percent * 0.6),
    88в†’        objective: progress.currentObjective,
    89в†’        feasible: progress.feasible,
    90в†’      });
    91в†’    });
    92в†’
    93в†’    // Update progress: storing results
    94в†’    await context.updateProgress({ stage: 'STORING_RESULTS', percent: 95 });
    95в†’    await context.log(`Optimization complete: ${result.summary.trainsAssigned} trains assigned`);
    96в†’
    97в†’    // Store run assignments to database for historical analysis
    98в†’    await storeOptimizationResults(date, input.requestId, result);
    99в†’
   100в†’    // Broadcast via WebSocket (to be implemented when WebSocket hub exists)
   101в†’    // await broadcastOptimizationComplete(date, fleetId, result);
   102в†’
   103в†’    // Update metrics
   104в†’    optimizerMetrics.trainsAssigned
   105в†’      .labels(fleetId)
   106в†’      .set(result.summary.trainsAssigned);
   107в†’
   108в†’    log.info(
   109в†’      {
   110в†’        jobId: id,
   111в†’        status: result.status,
   112в†’        trainsAssigned: result.summary.trainsAssigned,
   113в†’        trainsUnassigned: result.summary.trainsUnassigned,
   114в†’        solveTimeMs: result.solveTimeMs,
   115в†’      },
   116в†’      'Optimizer job complete'
   117в†’    );
   118в†’
   119в†’    return result;
   120в†’  });
   121в†’}
   122в†’
   123в†’/**
   124в†’ * Build optimizer input from database
   125в†’ */
   126в†’async function buildOptimizerInput(
   127в†’  date: string,
   128в†’  fleetId: string,
   129в†’  constraints?: OptimizerJobData['constraints'],
   130в†’  timeoutMs?: number
   131в†’): Promise<OptimizerFullInput> {
   132в†’  const requestId = crypto.randomUUID();
   133в†’
   134в†’  // Fetch fleet info
   135в†’  const fleet = await db.query.fleets.findFirst({
   136в†’    where: eq(fleets.id, fleetId),
   137в†’  });
