/**
 * MMS Run Assignment Solver Implementation
 *
 * Uses Google OR-Tools CP-SAT solver for constraint-based optimization.
 * Implements all hard/soft constraints from spec 004.
 */

#include "solver.h"
#include <ortools/sat/cp_model.h>
#include <chrono>
#include <algorithm>
#include <sstream>
#include <cmath>

#ifdef HAS_FMT
#include <fmt/format.h>
#else
#include <cstdio>
#endif

namespace mms {

using namespace operations_research::sat;

// =============================================================================
// JSON Serialization
// =============================================================================

json ExplanationFactor::toJson() const {
    return {
        {"constraint_type", constraintType},
        {"constraint_name", constraintName},
        {"impact", impact},
        {"description", description}
    };
}

json Assignment::toJson() const {
    json expJson = json::array();
    for (const auto& e : explanation) {
        expJson.push_back(e.toJson());
    }
    return {
        {"train_id", trainId},
        {"route_id", routeId},
        {"score", score},
        {"explanation", expJson}
    };
}

json Unassigned::toJson() const {
    json result;
    if (trainId) result["train_id"] = *trainId;
    if (routeId) result["route_id"] = *routeId;
    if (shortfall) result["shortfall"] = *shortfall;
    result["reason"] = reason;
    result["blocking_constraints"] = blockingConstraints;
    return result;
}

json MaterialWarning::toJson() const {
    return {
        {"pm_id", pmId},
        {"train_id", trainId},
        {"part_number", partNumber},
        {"status", status},
        {"description", description}
    };
}

json ResultSummary::toJson() const {
    json breakdown;
    for (const auto& [key, value] : softConstraintBreakdown) {
        breakdown[key] = value;
    }
    return {
        {"total_penalty", totalPenalty},
        {"trains_assigned", trainsAssigned},
        {"trains_unassigned", trainsUnassigned},
        {"soft_constraint_breakdown", breakdown},
        {"material_blocks", materialBlocks}
    };
}

json SolverResult::toJson() const {
    json assignmentsJson = json::array();
    for (const auto& a : assignments) {
        assignmentsJson.push_back(a.toJson());
    }

    json unassignedJson = json::array();
    for (const auto& u : unassigned) {
        unassignedJson.push_back(u.toJson());
    }

    json warningsJson = json::array();
    for (const auto& w : materialWarnings) {
        warningsJson.push_back(w.toJson());
    }

