   137в†’
   138в†’SolverResult MmsSolver::solve(const json& input, ProgressCallback onProgress) {
   139в†’    auto startTime = std::chrono::steady_clock::now();
   140в†’
   141в†’    // Parse input
   142в†’    std::string requestId = input["request_id"].get<std::string>();
   143в†’    auto trains = parseTrains(input);
   144в†’    auto routes = parseRoutes(input);
   145в†’    auto hardConstraints = parseHardConstraints(input);
   146в†’    auto softConstraints = parseSoftConstraints(input);
   147в†’    auto unavailabilityEvents = parseUnavailabilityEvents(input);
   148в†’    auto routeCompatibility = parseRouteCompatibility(input);
   149в†’    auto config = parseConfig(input);
   150в†’
   151в†’    // Build CP-SAT model
   152в†’    CpModelBuilder model;
   153в†’
   154в†’    // Decision variables: assign[t][r] = 1 if train t assigned to route r
   155в†’    std::vector<std::vector<BoolVar>> assign(trains.size());
   156в†’    for (size_t t = 0; t < trains.size(); ++t) {
   157в†’        assign[t].resize(routes.size());
   158в†’        for (size_t r = 0; r < routes.size(); ++r) {
   159в†’            assign[t][r] = model.NewBoolVar();
   160в†’        }
   161в†’    }
   162в†’
   163в†’    // =========================================================================
   164в†’    // HARD CONSTRAINTS
   165в†’    // =========================================================================
   166в†’
   167в†’    // 1. Each train assigned to at most one route
   168в†’    for (size_t t = 0; t < trains.size(); ++t) {
   169в†’        std::vector<BoolVar> trainRoutes;
   170в†’        for (size_t r = 0; r < routes.size(); ++r) {
   171в†’            trainRoutes.push_back(assign[t][r]);
   172в†’        }
   173в†’        model.AddAtMostOne(trainRoutes);
   174в†’    }
   175в†’
   176в†’    // 2. Route requirements (exactly N trains)
   177в†’    for (size_t r = 0; r < routes.size(); ++r) {
   178в†’        std::vector<BoolVar> routeTrains;
   179в†’        for (size_t t = 0; t < trains.size(); ++t) {
   180в†’            // Only include trains that are fleet-compatible
   181в†’            if (isFleetAllowed(trains[t], routes[r])) {
   182в†’                routeTrains.push_back(assign[t][r]);
   183в†’            } else {
   184в†’                // Force incompatible assignments to 0
   185в†’                model.AddEquality(assign[t][r], 0);
   186в†’            }
   187в†’        }
   188в†’
   189в†’        // Require exactly N trains for this route
   190в†’        if (routeTrains.size() >= static_cast<size_t>(routes[r].requiredTrains)) {
   191в†’            model.AddEquality(LinearExpr::Sum(routeTrains), routes[r].requiredTrains);
   192в†’        }
   193в†’    }
   194в†’
   195в†’    // 3. Fitness status - GROUNDED/RESTRICTED trains cannot be assigned
   196в†’    for (size_t t = 0; t < trains.size(); ++t) {
   197в†’        if (trains[t].fitnessStatus == "GROUNDED") {
