MmsSolver::MmsSolver() = default;

std::string MmsSolver::validateInput(const json& input) const {
    if (!input.contains("request_id")) {
        return "Missing required field: request_id";
    }
    if (!input.contains("trains") || !input["trains"].is_array()) {
        return "Missing or invalid field: trains (must be array)";
    }
    if (!input.contains("routes") || !input["routes"].is_array()) {
        return "Missing or invalid field: routes (must be array)";
    }
    if (input["trains"].empty()) {
        return "trains array is empty";
    }
    if (input["routes"].empty()) {
        return "routes array is empty";
    }
    return "";
}

SolverResult MmsSolver::solve(const json& input, ProgressCallback onProgress) {
    auto startTime = std::chrono::steady_clock::now();

    // Parse input
    std::string requestId = input["request_id"].get<std::string>();
    auto trains = parseTrains(input);
    auto routes = parseRoutes(input);
    auto hardConstraints = parseHardConstraints(input);
    auto softConstraints = parseSoftConstraints(input);
    auto unavailabilityEvents = parseUnavailabilityEvents(input);
    auto routeCompatibility = parseRouteCompatibility(input);
    auto config = parseConfig(input);

    // Build CP-SAT model
    CpModelBuilder model;

    // Decision variables: assign[t][r] = 1 if train t assigned to route r
    std::vector<std::vector<BoolVar>> assign(trains.size());
    for (size_t t = 0; t < trains.size(); ++t) {
        assign[t].resize(routes.size());
        for (size_t r = 0; r < routes.size(); ++r) {
            assign[t][r] = model.NewBoolVar();
        }
    }

    // =========================================================================
    // HARD CONSTRAINTS
    // =========================================================================

    // 1. Each train assigned to at most one route
    for (size_t t = 0; t < trains.size(); ++t) {
        std::vector<BoolVar> trainRoutes;
        for (size_t r = 0; r < routes.size(); ++r) {
            trainRoutes.push_back(assign[t][r]);
        }
        model.AddAtMostOne(trainRoutes);
    }

    // 2. Route requirements (exactly N trains)
    for (size_t r = 0; r < routes.size(); ++r) {
        std::vector<BoolVar> routeTrains;
        for (size_t t = 0; t < trains.size(); ++t) {
            // Only include trains that are fleet-compatible
            if (isFleetAllowed(trains[t], routes[r])) {
                routeTrains.push_back(assign[t][r]);
            } else {
                // Force incompatible assignments to 0
                model.AddEquality(assign[t][r], 0);
            }
        }

        // Require exactly N trains for this route
        if (routeTrains.size() >= static_cast<size_t>(routes[r].requiredTrains)) {
            model.AddEquality(LinearExpr::Sum(routeTrains), routes[r].requiredTrains);
        }
    }

    // 3. Fitness status - GROUNDED/RESTRICTED trains cannot be assigned
    for (size_t t = 0; t < trains.size(); ++t) {
        if (trains[t].fitnessStatus == "GROUNDED") {
            for (size_t r = 0; r < routes.size(); ++r) {
                model.AddEquality(assign[t][r], 0);
            }
        }
    }

    // 4. Hard constraints from input (PM_DUE, DEPOT_LOCK, etc.)
    for (const auto& constraint : hardConstraints) {
        size_t trainIdx = findTrainIndex(trains, constraint.trainId);
        if (trainIdx < trains.size()) {
            if (constraint.routeId) {
                // Block specific train-route combination
                size_t routeIdx = findRouteIndex(routes, *constraint.routeId);
                if (routeIdx < routes.size()) {
                    model.AddEquality(assign[trainIdx][routeIdx], 0);
                }
            } else {
                // Block train from all routes
                for (size_t r = 0; r < routes.size(); ++r) {
                    model.AddEquality(assign[trainIdx][r], 0);
                }
            }
        }
